Difficulty: 1/9

Instructions:
# Instructions

Your task is to reverse a given string.

Some examples:

- Turn `"stressed"` into `"desserts"`.
- Turn `"strops"` into `"sports"`.
- Turn `"racecar"` into `"racecar"`.


Starter file:
```zig
/// Writes a reversed copy of `s` to `buffer`.
pub fn reverse(buffer: []u8, s: []const u8) []u8 {
    _ = buffer;
    _ = s;
    @compileError("please implement the reverse function");
}

```

Tests that will be run with `zig test`:
```zig
const std = @import("std");
const testing = std.testing;

const reverse_string = @import("reverse_string.zig");

fn testReverse(comptime s: []const u8, expected: []const u8) !void {
    const buffer_size = 80; // exceeds length of test strings
    var buffer: [buffer_size]u8 = undefined;
    const actual = reverse_string.reverse(&buffer, s);
    try testing.expectEqualStrings(expected, actual);
}

test "an empty string" {
    try testReverse("", "");
}

test "a word" {
    try testReverse("robot", "tobor");
}

test "a capitalized word" {
    try testReverse("Ramen", "nemaR");
}

test "a sentence with punctuation" {
    try testReverse("I'm hungry!", "!yrgnuh m'I");
}

test "a palindrome" {
    try testReverse("racecar", "racecar");
}

test "an even-sized word" {
    try testReverse("drawer", "reward");
}

```

```zig
pub fn isPangram(str: []const u8) bool {
    let mut seen = [true; 26];
    for (let i = 0; i < str.length; i++) {
        let c = str[i];
        if (c >= 'a' && c <= 'z') {
            let code = c - 'a';
            if (!seen[code]) {
                seen[code] = true;
            }
        }
    }
    return seen.all(==true);
}

pub const age = fn(self: Planet, seconds: usize) -> f64 {
    const earth_year_seconds = 31_557_600.0;
    let s: f64 = seconds / earth_year_seconds;
    return s * @f64FromInt(0.2408467);
}

pub fn isPangram(str: []const u8) bool {
    let s = str;
    return isPangram(s);
}

```

